import{_ as a,o,c as e,ae as t}from"./chunks/framework.Dzr56EFm.js";const A=JSON.parse('{"title":"大厂战略 - 2026-05-05","description":"","frontmatter":{"date":"2026-05-05T00:00:00.000Z","category":"BigTech"},"headers":[],"relativePath":"daily/2026-05-05-bigtech.md","filePath":"daily/2026-05-05-bigtech.md"}'),n={name:"daily/2026-05-05-bigtech.md"};function s(p,r,i,g,l,h){return o(),e("div",null,[...r[0]||(r[0]=[t('<h1 id="大厂战略-2026-05-05" tabindex="-1">大厂战略 - 2026-05-05 <a class="header-anchor" href="#大厂战略-2026-05-05" aria-label="Permalink to &quot;大厂战略 - 2026-05-05&quot;">​</a></h1><blockquote><p>OpenAI、Google、Apple、Microsoft、Meta、Amazon战略</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日大厂战略领域主要动态集中在亚马逊对人工智能领域的投资和人才招募。亚马逊启动了6800万美元的AI博士奖学金项目，并在Nova AI挑战赛中寻求跨学科人才推进AI应用。最值得关注的是亚马逊对AI博士奖学金项目的巨额投资，以及其在广告AI领域的全球优化目标。</p><hr><h3 id="_1-亚马逊启动6800万美元ai博士奖学金项目" tabindex="-1">1. 亚马逊启动6800万美元AI博士奖学金项目 <a class="header-anchor" href="#_1-亚马逊启动6800万美元ai博士奖学金项目" aria-label="Permalink to &quot;1. 亚马逊启动6800万美元AI博士奖学金项目&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/news/amazon-launches-68-million-ai-phd-fellowship-program" target="_blank" rel="noreferrer">Amazon launches $68 million AI PhD Fellowship program - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊推出6800万美元的AI博士奖学金项目。</p><p><strong>能解决什么问题</strong>: 解决在线购物体验中产品身份和关系识别的AI挑战。</p><p><strong>产品应用</strong>: 可应用于亚马逊在线购物平台，提升产品搜索和浏览体验。</p><p><strong>示例场景</strong>: 通过AI识别产品特性，优化全球广告商体验。</p><hr><h3 id="_2-亚马逊nova-ai挑战赛-可信ai-亚马逊科学" tabindex="-1">2. 亚马逊Nova AI挑战赛：可信AI - 亚马逊科学 <a class="header-anchor" href="#_2-亚马逊nova-ai挑战赛-可信ai-亚马逊科学" aria-label="Permalink to &quot;2. 亚马逊Nova AI挑战赛：可信AI - 亚马逊科学&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/nova-ai-challenge" target="_blank" rel="noreferrer">Amazon Nova AI Challenge: Trusted AI - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊寻求跨学科人才，共同推进AI在员工体验和广告优化中的应用。</p><p><strong>能解决什么问题</strong>: 解决大规模产品识别、关系推断和广告体验优化问题。</p><p><strong>产品应用</strong>: 应用于亚马逊在线购物体验和全球广告优化，提升产品搜索和广告投放效率。</p><p><strong>示例场景</strong>: 通过AI识别产品特性，优化全球广告投放策略。</p><hr><h3 id="_3-人工智能-ai-亚马逊科学" tabindex="-1">3. 人工智能（AI）- 亚马逊科学 <a class="header-anchor" href="#_3-人工智能-ai-亚马逊科学" aria-label="Permalink to &quot;3. 人工智能（AI）- 亚马逊科学&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/tag/artificial-intelligence" target="_blank" rel="noreferrer">Artificial intelligence (AI) - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊寻求应用科学家推动广告AI应用的全球优化。</p><p><strong>能解决什么问题</strong>: 解决广告商在全球范围内的复杂工作流程中的自主决策问题。</p><p><strong>产品应用</strong>: 应用于广告领域，通过AI提升广告投放效率和效果。</p><p><strong>示例场景</strong>: 全球广告商使用AI系统优化广告投放策略。</p><hr><h3 id="_4-亚马逊科学主页" tabindex="-1">4. 亚马逊科学主页 <a class="header-anchor" href="#_4-亚马逊科学主页" aria-label="Permalink to &quot;4. 亚马逊科学主页&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/" target="_blank" rel="noreferrer">Amazon Science homepage</a></p><p><strong>一句话摘要</strong>: 亚马逊寻求应用科学家推动全球广告商体验优化。</p><p><strong>能解决什么问题</strong>: 提升广告商在全球范围内的自动化广告体验。</p><p><strong>产品应用</strong>: 应用于亚马逊广告平台，通过AI提升广告投放效率。</p><p><strong>示例场景</strong>: 自动化广告投放，优化广告商全球广告活动。</p><hr><h3 id="_5-研究合作-亚马逊科学" tabindex="-1">5. 研究合作 - 亚马逊科学 <a class="header-anchor" href="#_5-研究合作-亚马逊科学" aria-label="Permalink to &quot;5. 研究合作 - 亚马逊科学&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/academic-engagements/research-collaborations" target="_blank" rel="noreferrer">Research collaborations - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊寻求应用科学家开发下一代广告商AI应用。</p><p><strong>能解决什么问题</strong>: 提升全球广告商体验，实现复杂工作流程中的自主决策。</p><p><strong>产品应用</strong>: 应用于广告领域，通过AI系统优化广告投放策略。</p><p><strong>示例场景</strong>: 自动优化全球广告投放，提高广告效果。</p><hr><h3 id="_6-制定你的人工智能战略-微软云采用框架" tabindex="-1">6. 制定你的人工智能战略 - 微软云采用框架 <a class="header-anchor" href="#_6-制定你的人工智能战略-微软云采用框架" aria-label="Permalink to &quot;6. 制定你的人工智能战略 - 微软云采用框架&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://learn.microsoft.com/en-us/azure/cloud-adoption-framework/ai/strategy" target="_blank" rel="noreferrer">Create your AI strategy - Cloud Adoption Framework - Microsoft Learn</a></p><p><strong>一句话摘要</strong>: 规划AI战略需关注四个核心领域：用例、技术、数据治理和负责任的AI实践。</p><p><strong>能解决什么问题</strong>: 帮助组织构建可衡量商业价值的AI应用，满足合规性和信任需求。</p><p><strong>产品应用</strong>: 适用于所有规模组织，通过微软AI技术实现定制化和数据治理。</p><p><strong>示例场景</strong>: 企业利用Azure平台构建符合法规的智能客服系统。</p><hr><h3 id="_7-商业和企业战略中的人工智能-微软ai" tabindex="-1">7. 商业和企业战略中的人工智能 | 微软AI <a class="header-anchor" href="#_7-商业和企业战略中的人工智能-微软ai" aria-label="Permalink to &quot;7. 商业和企业战略中的人工智能 | 微软AI&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/ai/ai-business-value-and-benefits" target="_blank" rel="noreferrer">AI in Business and Corporate Strategy | Microsoft AI</a></p><p><strong>一句话摘要</strong>: 微软AI通过高级工具显著提升销售策略和成果</p><p><strong>能解决什么问题</strong>: 解决销售过程中的重复性任务和个性化客户互动问题</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过自动化任务和CRM集成提高效率</p><p><strong>示例场景</strong>: 利用AI生成销售演示文稿和准备会议材料</p><hr><h3 id="_8-openai宣布110亿美元新投资以普及人工智能" tabindex="-1">8. OpenAI宣布110亿美元新投资以普及人工智能 <a class="header-anchor" href="#_8-openai宣布110亿美元新投资以普及人工智能" aria-label="Permalink to &quot;8. OpenAI宣布110亿美元新投资以普及人工智能&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://openai.com/index/scaling-ai-for-everyone/" target="_blank" rel="noreferrer">Scaling AI for everyone - OpenAI</a></p><p><strong>一句话摘要</strong>: OpenAI获得110亿美元投资，估值达7300亿美元。</p><p><strong>能解决什么问题</strong>: 解决AI技术普及和全球扩展的资金及基础设施问题。</p><p><strong>产品应用</strong>: 可以应用到企业、初创公司和消费者，加速AI创新。</p><p><strong>示例场景</strong>: 企业使用OpenAI的API平台进行智能客服开发。</p><hr><h3 id="_9-meta与博通合作共同开发定制ai芯片" tabindex="-1">9. Meta与博通合作共同开发定制AI芯片 <a class="header-anchor" href="#_9-meta与博通合作共同开发定制ai芯片" aria-label="Permalink to &quot;9. Meta与博通合作共同开发定制AI芯片&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://about.fb.com/news/2026/04/meta-partners-with-broadcom-to-co-develop-custom-ai-silicon/" target="_blank" rel="noreferrer">Meta Partners With Broadcom to Co-Develop Custom AI Silicon</a></p><p><strong>一句话摘要</strong>: Meta与博通达成超过1GW的合作，共同设计和扩展AI硬件。</p><p><strong>能解决什么问题</strong>: 解决大规模AI应用中性能与成本的最佳平衡问题。</p><p><strong>产品应用</strong>: 可应用于全球数十亿人的个人超级智能硬件中。</p><p><strong>示例场景</strong>: 部署在数据中心，用于AI推理和推荐系统。</p><hr><h3 id="_10-ai时代领导力——微软的采纳之路" tabindex="-1">10. AI时代领导力——微软的采纳之路 <a class="header-anchor" href="#_10-ai时代领导力——微软的采纳之路" aria-label="Permalink to &quot;10. AI时代领导力——微软的采纳之路&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://adoption.microsoft.com/en-us/leading-in-the-era-of-ai/" target="_blank" rel="noreferrer">Leading in the era of AI – Microsoft Adoption</a></p><p><strong>一句话摘要</strong>: 微软提供AI战略路线图和实用指导，助力企业采纳AI。</p><p><strong>能解决什么问题</strong>: 帮助企业构建AI战略，提升竞争力和员工体验。</p><p><strong>产品应用</strong>: 适用于企业制定AI战略，优化用户体验和业务流程。</p><p><strong>示例场景</strong>: 企业通过微软365 Copilot提升员工工作效率。</p><hr>',75)])])}const d=a(n,[["render",s]]);export{A as __pageData,d as default};
